values.value:
{
  "summary": "Get Account by Id",
  "description": "Retrieve a Salesforce Account record",
  "parameters": [
    {
      "name": "id",
      "in": "path",
      "required": true,
      "schema": {
        "type": "string"
      }
    }
  ],
  "responses": {
    "200": {
      "description": "Account found",
      "content": {
        "application/json": {
          "schema": {
            "type": "object",
            "properties": {
              "Id": { "type": "string" },
              "Name": { "type": "string" },
              "Industry": { "type": "string" }
            }
          }
        }
      }
    },
    "404": {
      "description": "Account not found"
    }
  }
}
